#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const ll MOD = 1e9 + 7;
#define all(a) (a).begin(), (a).end()
#define cin_vec(x)                    \
    for (ll i = 0; i < x.size(); i++) \
    {                                 \
        cin >> x[i];                  \
    }
#define cout_vecn(x)                  \
    for (ll i = 0; i < x.size(); i++) \
    {                                 \
        cout << x[i] << endl;         \
    }
#define cout_vec(x)                   \
    for (ll i = 0; i < x.size(); i++) \
    {                                 \
        cout << x[i] << " ";          \
    }                                 \
    cout << endl;
int main()
{
    string s,t;
    cin>>s>>t;
    map<string,ll> x;
    for(int i=0;i<s.size();i++)
    {
        string u;
        u.push_back(s[i]);
        x[u]+=s.size()-i;
        for(int j=i+1;j<s.size();j++)
        {
            u.push_back(s[j]);
          x[u]+=s.size()-j;
        }
    }
    ll ans=0;
    for(int i=0;i<t.size();i++)
    {
        string u;
        u.push_back(t[i]);
      ll a=x[u];
        ans+=a;
        for(int j=i+1;j<t.size();j++)
        {
            u.push_back(t[j]);
          a+=x[u];
            ans+=a;
        }
    }
    cout<<ans<<endl;
}
